void processData() {
    int value = 42;

    // Function declaration at block scope - Noncompliant
    void helperFunction(int x);

    // This looks like function declaration but is variable declaration
    std::string name(); // Noncompliant - actually declares a variable
    short result(short(value)); // Noncompliant - confusing syntax
